    },
    {
      "n": 41,
      "column": "left",
      "text": "KUNGS/ lai nahkahs\nman tawa Scheblastiba/ tawa\nPefifchana pehz tawa Wahrdâ.\n"
    },
    {
      "n": 42,
      "column": "left",
      "text": "Ka es mannam Mehdita-\njam warru atbildelt / jo es pa-\ntaujohs us tawu Wahrdn.\n"
    },
    {
      "n": 43,
      "column": "left",
      "text": "Un ne atrauji wiffai to\nPateefibas Wahrdn no mannas\nMuttês/ jo es zerreju ustawahm\nTeesfahn.\n"
    },
    {
      "n": 44,
      "column": "left",
      "text": "Es turreschu tawu Bauf-\nlibu weenumebr/ muhschigi muh-\nscham.\n"
    },
    {
      "n": 45,
      "column": "left",
      "text": "Un es staigaju bes Isbai-\nlehni/ jo es metkeju tawas Pa-\nwehlefchanas.\n"
    },
    {
      "n": 46,
      "column": "left",
      "text": "Ir no tawahm Lcezibahm\nrunnaju es preeſch Kehnineem/\nun ne kaunohs.\n"
    },
    {
      "n": 47,
      "column": "left",
      "text": "Un es preezajohs eekſch\ntaweem Bausfleem/ ko es mihleju.\n"
    },
    {
      "n": 48,
      "column": "left",
      "text": "Un es pazelfchn tawas\nRohfas pee taweem Bausfleem/\nes mihleju/ un pahrdohma-\nn tawus Likkunus.\n"
    },
    {
      "n": 49,
      "column": "left",
      "text": "Peeminni to Wahrdn ta-\n"
    },
    {
      "n": 50,
      "column": "right",
      "text": "Schi irr manna Eepr-\nzinatchana eekſch mannahm Be-\ndahm / jo tawa Apfohlichan\nmann dshwu padarra.\n"
    },
    {
      "n": 51,
      "column": "right",
      "text": "Tee Lepnee irr mannu fo-\nti apmebdijschi/ (tatschu) es u-\ntawas Bauflibas ne atkahpju.\n"
    },
    {
      "n": 52,
      "column": "right",
      "text": "KUNGS/ kad es pe-\nmifnu/ ka tu no Eefahkuma e-\nfohdijs / tad tohpu es eepreez-\nnahts.\n"
    },
    {
      "n": 53,
      "column": "right",
      "text": "Istrubzinaschana irr man-\nni atsehmuſi to Besdeewig-\npehz/kas tawu Bauflibu painett\n"
    },
    {
      "n": 54,
      "column": "right",
      "text": "Tawi Likkumi irr ma-\npar Dseefmahm mannas Swe-\nſchibas Namnâ.\n"
    },
    {
      "n": 55,
      "column": "right",
      "text": "KUNGS/ Nakti pee-\nminnu es tawu Wahrdn/ un-\npafargu tawu Baufli.\n"
    },
    {
      "n": 56,
      "column": "right",
      "text": "Ta irr manna *(Man-\nta)/ ka es tawas Pawehletcha-\nnas turru.\n"
    },
    {
      "n": 57,
      "column": "right",
      "text": "Tas KUNGS irr man-\nna Datta/ es efinu fazzifs: Ka-\nes gribbu tawus Wahrdus tur-\nreht.\n"
    },
    {
      "n": 58,
      "column": "right",
      "text": "Es luhdsu tawâ Preek-\nſcha no wiffas Sirde/ eſſi man\nſchehligs pehz tawas Apfohli-\nſchanas.\n"
    },
    {
      "n": 59,
      "column": "right",
      "text": "Es apdohmaju mannus\nZelfus / un atgreeschu mannas\nRahjas pee tawahm Leczibahm.\n"
    },
    {
      "n": 60,
      "column": "right",
      "text": "Es steidsohs un ne kawe-\njohs tawus Bauflus turreht.\n"
